1	/**
2	 * Content script on Google Calendar — the DOM layer of the hybrid model.
3	 *
4	 * It reads the open event surface (detail popover / expanded edit) to:
5	 *  - GATE the "Manage Visitors" button on the magic address being a guest,
6	 *  - capture the `data-eventid` (base64url "<eventId> <calendarId>"), and
7	 *  - take a best-effort SNAPSHOT (guest emails) so the panel can paint instantly
8	 *    and cover the unsaved (no-API) case.
9	 * The API layer (background) remains the authoritative source. We read only the
10	 * semantic `data-eventid`, the `[role="dialog"]` ARIA signal, and the surface's
11	 * visible text — no layout/CSS-class coupling, no injection into Google's markup.
12	 */
13	import { MAGIC_ADDRESS } from '@/lib/config';
14	import {
15	  ACTIVE_EID_KEY,
16	  ACTIVE_SNAPSHOT_KEY,
17	  AUTH_LAPSED,
18	  NUDGE_TARGETS,
19	  PANEL_STATE,
20	} from '@/lib/messaging';
21	import type { DomEventSnapshot, VisitorEventSummary } from '@/lib/types';
22	
23	/** True while our extension context is still valid. After an extension reload or
24	 *  update, this content script is orphaned: every `chrome.*` call then throws
25	 *  "Extension context invalidated" (synchronously — `.catch()` can't see it). We
26	 *  check this before touching any chrome API so an orphan stops quietly. */
27	const extAlive = (): boolean => {
28	  try {
29	    return !!chrome.runtime?.id;
30	  } catch {
31	    return false;
32	  }
33	};
34	
35	/** sendMessage that never throws or rejects, even once the context is gone. */
36	function safeSend<T = unknown>(message: unknown): Promise<T | undefined> {
37	  if (!extAlive()) return Promise.resolve(undefined);
38	  try {
39	    return Promise.resolve(chrome.runtime.sendMessage(message)).catch(() => undefined);
40	  } catch {
41	    return Promise.resolve(undefined);
42	  }
43	}
44	
45	/** storage.session helpers that no-op once the context is gone. */
46	function safeStorageGet(key: string): Promise<Record<string, unknown>> {
47	  if (!extAlive()) return Promise.resolve({});
48	  try {
49	    return Promise.resolve(chrome.storage.session.get(key)).catch(() => ({}));
50	  } catch {
51	    return Promise.resolve({});
52	  }
53	}
54	function safeStorageSet(items: Record<string, unknown>): Promise<void> {
55	  if (!extAlive()) return Promise.resolve();
56	  try {
57	    return Promise.resolve(chrome.storage.session.set(items)).catch(() => {});
58	  } catch {
59	    return Promise.resolve();
60	  }
61	}
62	
63	export default defineContentScript({
64	  matches: ['https://calendar.google.com/*'],
65	  main() {
66	    // The id of the most recently clicked event chip — the event whose popover
67	    // is opening. Reset when the surface closes so a later unrelated dialog
68	    // can't resurrect a stale button.
69	    let clickedEid: string | null = null;
70	    let lastSnapshot: DomEventSnapshot | null = null;
71	    let panelOpen = false;
72	    // The dialog node we've accepted as an event surface. Held so recognition is
73	    // sticky for the life of that node (see readSurface) — kills the button flicker.
74	    let eventDialog: HTMLElement | null = null;
75	    let followedEid: string | null = null; // last event auto-pushed to the panel
76	    let pendingMagic: { eid: string; eventId: string; title: string } | null = null;
77	    let everSawEventId = false;
78	
79	    // Button UI: a native injected button when a clean anchor exists, else a
80	    // floating fallback (Idea 2). The magic-address gate is dropped — the button
81	    // shows on any open event surface; clicking it IS the intent.
82	    const button = createButtonUI(() => {
83	      if (!lastSnapshot) return;
84	      // Always hand the click to the background as OPEN_FOR_EVENT. The
85	      // background is the single authority on whether the panel is connected
86	      // (it owns the panel's port): it calls sidePanel.open only when the panel
87	      // is closed, and otherwise just points the open panel at this event. We
88	      // deliberately do NOT branch on a local panelOpen/opening flag here — those
89	      // drift out of sync (a missed PANEL_STATE, or a failed open leaving a latch
90	      // stuck) and were the reason a click sometimes silently did nothing.
91	      openFor(lastSnapshot);
92	      // Note: we intentionally do NOT navigate the tab to the event here. The
93	      // panel resolves the event itself (Calendar API), so reloading the page
94	      // adds nothing but cost + surprise. "Open in Calendar" in the panel is the
95	      // explicit, user-initiated way to jump to the event.
96	    });
97	
98	    // In-page nudge banner: visitor events the user saved but hasn't acted on.
99	    // Driven by the background sync (robust), not live DOM scanning.
100	    const nudge = mountNudge();
101	    safeSend<{ ok?: boolean; data?: VisitorEventSummary[] }>({ type: 'GET_NUDGE_TARGETS' }).then(
102	      (res) => {
103	        if (res?.ok) nudge.setTargets(res.data as VisitorEventSummary[]);
104	      },
105	    );
106	
107	    // Reconnect banner: shown when the background reports a recoverable auth lapse
108	    // (the user was connected but a silent token renew failed), so nudging never
109	    // dies silently. The background broadcasts AUTH_LAPSED on each sync.
110	    const reconnect = mountReconnect(() => safeSend({ type: 'OPEN_PANEL' }));
111	
112	    // Seed the panel-open state on (re)load so auto-follow works after a
113	    // same-tab navigation (the panel persists; this content script is fresh).
114	    safeSend<{ ok?: boolean; data?: { open: boolean } }>({ type: 'GET_PANEL_STATE' }).then((res) => {
115	      if (res?.ok) {
116	        panelOpen = !!res.data?.open;
117	        nudge.setPanelOpen(panelOpen);
118	        reconnect.setPanelOpen(panelOpen);
119	        render();
120	      }
121	    });
122	
123	    // Fast detection: sync on load, on tab focus, and right after leaving the
124	    // event editor (a likely save) — so the banner appears in seconds, not up
125	    // to a minute, and shows immediately when the user returns to the tab.
126	    let lastSync = 0;
127	    const syncNow = () => {
128	      const now = Date.now();
129	      if (now - lastSync < 4000) return; // throttle
130	      lastSync = now;
131	      safeSend({ type: 'SYNC_NOW' });
132	    };
133	    // Burst: fire several syncs after a likely save to beat Google's API
134	    // eventual-consistency lag (a fresh events.list may not show the just-saved
135	    // event for a few seconds).
136	    let lastBurst = 0;
137	    const syncBurst = () => {
138	      const now = Date.now();
139	      if (now - lastBurst < 2000) return;
140	      lastBurst = now;
141	      for (const d of [0, 3000, 8000]) {
142	        setTimeout(() => safeSend({ type: 'SYNC_NOW' }), d);
143	      }
144	    };
145	    syncNow();
146	    document.addEventListener('visibilitychange', () => {
147	      if (document.visibilityState === 'visible') syncNow();
148	    });
149	    window.addEventListener('focus', syncNow);
150	    let wasEditor = /\/eventedit/.test(location.pathname);
151	    const editorPoll = setInterval(() => {
152	      if (!extAlive()) return teardown(); // orphaned by an extension reload → stop
153	      const isEditor = /\/eventedit/.test(location.pathname);
154	      if (wasEditor && !isEditor) syncBurst(); // left the editor → likely saved
155	      wasEditor = isEditor;
156	      // Safety net: re-assert the button. The MutationObserver is debounced, so a
157	      // continuous scroll (which fires mutations faster than the debounce) can
158	      // starve it and never re-run render after Google re-renders the modal and
159	      // drops our injected button. This guarantees it comes back within ~1s.
160	      render();
161	    }, 1000);
162	
163	    // Stop all work once our context is invalidated (extension reloaded/updated),
164	    // so an orphaned script doesn't keep observing/polling — and remove our now-
165	    // dead button (its click can't reach the background) instead of leaving a
166	    // zombie that looks live but does nothing.
167	    let disposed = false;
168	    function teardown() {
169	      if (disposed) return;
170	      disposed = true;
171	      clearInterval(editorPoll);
172	      observer.disconnect();
173	      button.update(false);
174	    }
175	
176	    /** Read the open event surface, or null if none is open. `eid` may be '' for
177	     *  a brand-new, not-yet-saved event (no data-eventid / URL eid yet). */
178	    function readSurface(): { el: HTMLElement; eid: string } | null {
179	      const fromUrl = urlEid();
180	      const dialog = document.querySelector('[role="dialog"]') as HTMLElement | null;
181	      // A dialog that isn't an event surface — e.g. Google's "Send update emails
182	      // to existing guests?" save confirmation — must NEVER host our button, and
183	      // while one is open we suppress entirely so we don't inject onto it (or
184	      // behind it, over the editor). This is what kept the button appearing on
185	      // unrelated dialogs and "flashing" away when such a dialog opened/closed.
186	      if (dialog) {
187	        // Sticky recognition: once a dialog node is accepted as an event
188	        // surface, keep treating it as one until it actually leaves the DOM.
189	        // Google re-renders the popover's innards constantly; isEventDialog is a
190	        // heuristic, so a single tick where it momentarily reads false would
191	        // otherwise yank the button and pop it back a frame later — the flicker.
192	        // A genuinely different dialog (a confirmation) is a different node, so
193	        // it's still evaluated strictly and correctly rejected.
194	        const isEvent = dialog === eventDialog || isEventDialog(dialog);
195	        if (!isEvent) return null;
196	        eventDialog = dialog;
197	      } else {
198	        eventDialog = null;
199	      }
200	      if (fromUrl) {
201	        return { el: dialog ?? document.body, eid: fromUrl };
202	      }
203	      // Full-screen create/edit editor. An existing event always carries its eid
204	      // in the URL (handled above), so reaching here means a brand-new, unsaved
205	      // event → eid ''. Never fall back to clickedEid: it can be stale from a
206	      // previously viewed event and would point the panel at the wrong one.
207	      if (/\/eventedit/.test(location.pathname)) {
208	        return { el: dialog ?? document.body, eid: '' };
209	      }
210	      // Detail / quick-create popover.
211	      if (dialog) return { el: dialog, eid: clickedEid ?? '' };
212	      return null;
213	    }
214	
215	    function snapshotOf(el: HTMLElement, eid: string): DomEventSnapshot {
216	      const text = el.innerText || '';
217	      const lower = text.toLowerCase();
218	      const magicPresent = !!MAGIC_ADDRESS && lower.includes(MAGIC_ADDRESS);
219	      const guestEmails = extractEmails(text).filter(
220	        (e) => e.toLowerCase() !== MAGIC_ADDRESS,
221	      );
222	      // Best-effort title (cosmetic — the API sync replaces it). The full editor
223	      // exposes the title as a text input; the detail popover (the common case)
224	      // shows it as a heading, not an input — so fall back to the open dialog's
225	      // heading / accessible name. Scoped to the dialog so we never grab the
226	      // page's own H1 ("Calendar") when no event surface is open.
227	      const titleInput = el.querySelector(
228	        'input[aria-label*="title" i], input[placeholder*="title" i]',
229	      ) as HTMLInputElement | null;
230	      const dialog = el.matches?.('[role="dialog"]')
231	        ? el
232	        : el.querySelector<HTMLElement>('[role="dialog"]');
233	      const heading = dialog?.querySelector<HTMLElement>('[role="heading"], h1, h2');
234	      const title =
235	        titleInput?.value?.trim() ||
236	        heading?.innerText?.trim() ||
237	        dialog?.getAttribute('aria-label')?.trim() ||
238	        undefined;
239	      return { eid, magicPresent, guestEmails, title };
240	    }
241	
242	    function render() {
243	      if (!extAlive()) return teardown(); // orphaned by an extension reload → stop
244	      const surface = readSurface();
245	      lastSnapshot = surface ? snapshotOf(surface.el, surface.eid) : null;
246	
247	      // Instant nudge: while viewing a visitor event WITH a real eid, remember
248	      // it; when the user then leaves that surface (closed popover / saved &
249	      // left editor), show the nudge for it IMMEDIATELY — no API round-trip.
250	      if (lastSnapshot?.magicPresent && lastSnapshot.eid) {
251	        pendingMagic = {
252	          eid: lastSnapshot.eid,
253	          eventId: decodeEventId(lastSnapshot.eid),
254	          title: lastSnapshot.title ?? '',
255	        };
256	      } else if (!surface && pendingMagic) {
257	        nudge.addOptimistic({
258	          eid: pendingMagic.eid,
259	          eventId: pendingMagic.eventId,
260	          iCalUid: '',
261	          title: pendingMagic.title,
262	          start: undefined,
263	        });
264	        syncBurst(); // confirm/refresh from the API right after
265	        pendingMagic = null;
266	      }
267	
268	      // Show the button on any open event surface — including while the panel is
269	      // open. We keep the floating fallback available even then: a missing button
270	      // reads as broken (the user's report), and the native in-popover button can
271	      // lose the first-open injection race. The grace period in update() still
272	      // lets the native button win whenever it injects in time, so the FAB only
273	      // appears as a genuine last resort. (We no longer navigate the tab on click,
274	      // so the old "flash while a navigated page loads" concern is moot.)
275	      button.update(!!surface);
276	      if (panelOpen) maybeFollow();
277	    }
278	
279	    /** Push the open *saved* event to the panel so it follows what you're viewing.
280	     *  Saved only (non-empty eid); deduped; the panel guards against switching
281	     *  mid-action. */
282	    function maybeFollow() {
283	      const snap = lastSnapshot;
284	      if (!snap || !snap.eid) return; // new/unsaved events don't auto-switch
285	      if (snap.eid === followedEid) return;
286	      followedEid = snap.eid;
287	      safeSend({ type: 'FOLLOW_EVENT', eid: snap.eid, snapshot: snap });
288	    }
289	
290	    document.addEventListener(
291	      'click',
292	      (e) => {
293	        const chip = (e.target as Element | null)?.closest?.('[data-eventid]');
294	        const id = chip?.getAttribute('data-eventid');
295	        if (id) {
296	          everSawEventId = true;
297	          clickedEid = id;
298	        }
299	        // Re-check a few times: Google paints the popover progressively, so a
300	        // single 60ms probe can land before the surface (or its rows) exist,
301	        // and we'd then wait up to a second for the safety-net poll. Staggered
302	        // probes catch a slow paint quickly; render() is idempotent + cheap.
303	        for (const d of [60, 250, 600]) setTimeout(render, d);
304	      },
305	      true,
306	    );
307	
308	    document.addEventListener(
309	      'keydown',
310	      (e) => {
311	        if (e.key === 'Escape') {
312	          clickedEid = null;
313	          setTimeout(render, 60);
314	        }
315	      },
316	      true,
317	    );
318	
319	    // Detect surface open/close + edits (e.g. adding the magic address live).
320	    let timer: number | undefined;
321	    const observer = new MutationObserver(() => {
322	      clearTimeout(timer);
323	      timer = setTimeout(() => {
324	        if (!document.querySelector('[role="dialog"]') && !urlEid()) {
325	          clickedEid = null;
326	        }
327	        render();
328	      }, 150) as unknown as number;
329	    });
330	    observer.observe(document.body, { childList: true, subtree: true });
331	
332	    window.addEventListener('popstate', render);
333	
334	    // Hide the in-page button while the side panel is open.
335	    chrome.runtime.onMessage.addListener(
336	      (msg: {
337	        type?: string;
338	        open?: boolean;
339	        targets?: VisitorEventSummary[];
340	        cancelled?: string[];
341	        lapsed?: boolean;
342	      }) => {
343	        if (msg?.type === PANEL_STATE) {
344	          panelOpen = !!msg.open;
345	          if (!panelOpen) followedEid = null; // re-follow next time it opens
346	          nudge.setPanelOpen(panelOpen); // banner hides while the panel is open
347	          reconnect.setPanelOpen(panelOpen);
348	          render();
349	        } else if (msg?.type === NUDGE_TARGETS) {
350	          nudge.setTargets(msg.targets ?? [], msg.cancelled ?? []);
351	        } else if (msg?.type === AUTH_LAPSED) {
352	          reconnect.setLapsed(!!msg.lapsed);
353	        }
354	      },
355	    );
356	
357	    setTimeout(() => {
358	      if (!everSawEventId && !document.querySelector('[data-eventid]')) {
359	        console.warn(
360	          '[auxilio] no [data-eventid] found — click detection may be unavailable; use the panel’s event list.',
361	        );
362	      }
363	    }, 90_000);
364	
365	    render();
366	    console.log('[auxilio] content script ready on Google Calendar');
367	  },
368	});
369	
370	function openFor(snapshot: DomEventSnapshot) {
371	  return safeSend({ type: 'OPEN_FOR_EVENT', eid: snapshot.eid, snapshot });
372	}
373	
374	/** Event id from the expanded-edit URL path, if present. */
375	function urlEid(): string | null {
376	  const path = location.pathname.match(/\/eventedit\/([^/?#]+)/);
377	  if (path && path[1] !== 'eventedit') return safeDecode(path[1]);
378	  const q = new URLSearchParams(location.search).get('eid');
379	  return q ? safeDecode(q) : null;
380	}
381	
382	/** Pull unique email-looking strings from text (best-effort guest scrape). */
383	function extractEmails(text: string): string[] {
384	  const matches = text.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi) ?? [];
385	  return [...new Set(matches.map((m) => m.toLowerCase()))];
386	}
387	
388	/** eid (base64url of "<eventId> <calendarId>") → eventId, for nudge dedup. */
389	function decodeEventId(eid: string): string {
390	  try {
391	    let b64 = eid.replace(/-/g, '+').replace(/_/g, '/');
392	    b64 += '='.repeat((4 - (b64.length % 4)) % 4);
393	    return atob(b64).split(' ')[0] || '';
394	  } catch {
395	    return '';
396	  }
397	}
398	
399	function safeDecode(s: string): string {
400	  try {
401	    return decodeURIComponent(s);
402	  } catch {
403	    return s;
404	  }
405	}
406	
407	const USERS_SVG = `
408	<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24"
409	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
410	  <path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/>
411	  <path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>`;
412	
413	const LABEL = 'Manage Visitors';
414	const INJECT_ID = 'auxilio-manage-visitors';
415	
416	/**
417	 * Button UI manager: injects a native-styled "Manage Visitors" button as a real,
418	 * full-width row in the surface — below the Availability/Visibility section on the
419	 * edit page, at the bottom of the outermost content list in the detail popover (so
420	 * it scrolls with the rest of the UI, never an overlay) — and falls back to a
421	 * floating button only when no anchor is found. `update(show)` decides per render.
422	 */
423	function createButtonUI(onClick: () => void) {
424	  const fab = mountFloating(onClick);
425	  let injected: HTMLElement | null = null;
426	  let retryTimer: ReturnType<typeof setTimeout> | undefined;
427	
428	  // A clean injection anchor: where to drop the button + how far to indent it so
429	  // it lines up with the section's content column (past Google's icon gutter).
430	  // `inline` = sit next to a native button instead of as its own row.
431	  type Anchor = { insert: (el: HTMLElement) => void; inset: number; inline?: boolean };
432	
433	  /** Text/ARIA-based only — never CSS classes — so we stay decoupled from
434	   *  Google's obfuscated markup. Places the button where it reads as part of the
435	   *  form: between Description and the next section on the edit page, and as the
436	   *  last row of the detail popover's content list. Floating only as last resort. */
437	  function findAnchor(): Anchor | null {
438	    // Full-screen edit page → our own row just BELOW the Availability/Visibility
439	    // info section (falling back to above Description).
440	    if (/\/eventedit/.test(location.pathname)) {
441	      const avail = findAvailabilityInfo();
442	      const afterAvail = avail ? rowsListFor(avail) : null;
443	      if (afterAvail) {
444	        const { list, row } = afterAvail;
445	        return { insert: (el) => list.insertBefore(el, row.nextSibling), inset: rowInset(row, list) };
446	      }
447	      const desc = findEditDescription();
448	      const aboveDesc = desc ? rowsListFor(desc) : null;
449	      if (aboveDesc) {
450	        const { list, row } = aboveDesc;
451	        return { insert: (el) => list.insertBefore(el, row), inset: rowInset(row, list) };
452	      }
453	      // Fallback within the edit page: inline, right before the native "Save".
454	      const save = findButtonByText('save');
455	      const parent = save?.parentElement;
456	      if (save && parent) return { insert: (el) => parent.insertBefore(el, save), inset: 0, inline: true };
457	      return null;
458	    }
459	    // Detail popover / modal → BOTTOM of the OUTERMOST content list (after every
460	    // section, including the guest list). Robust whether or not guests exist.
461	    const dialog = document.querySelector<HTMLElement>('[role="dialog"]');
462	    if (dialog) {
463	      const list = findContentList(dialog);
464	      if (list) {
465	        const ref = firstIconLedRow(list);
466	        return { insert: (el) => list.appendChild(el), inset: ref ? rowInset(ref, list) : 0 };
467	      }
468	      // Fallback → bottom of the scrolling content.
469	      const scope = scrollContainer(dialog) ?? dialog;
470	      const l = mainVerticalList(scope) ?? scope;
471	      return { insert: (el) => l.appendChild(el), inset: 0 };
472	    }
473	    return null;
474	  }
475	
476	  function ensureInjected(): boolean {
477	    if (injected && injected.isConnected) return true; // still placed — skip the scan
478	    const anchor = findAnchor();
479	    if (!anchor) return false;
480	    removeInjected();
481	    ensureInjectedStyles();
482	    injected = anchor.inline
483	      ? buildInlineButton(onClick)
484	      : buildInjectedRow(onClick, anchor.inset);
485	    anchor.insert(injected);
486	    return true;
487	  }
488	
489	  function removeInjected() {
490	    injected?.remove();
491	    injected = null;
492	  }
493	
494	  return {
495	    // `allowFab` gates the floating fallback. It's only there to surface the
496	    // panel when we can't inject a native button; with the panel already open
497	    // it's redundant (auto-follow handles the viewed event), and it would flash
498	    // at the corner while a navigated page is still loading. So callers pass
499	    // false when the panel is open.
500	    update(show: boolean, allowFab = true) {
501	      clearTimeout(retryTimer);
502	      if (!show) {
503	        removeInjected();
504	        fab.setVisible(false);
505	        return;
506	      }
507	      // Try to inject now; if the anchor isn't in the DOM / laid out yet (Google
508	      // is still rendering the surface), keep retrying for a few seconds. The
509	      // MutationObserver covers DOM changes, but layout can settle — giving
510	      // elements their width — without a childList mutation, so width-based
511	      // anchor checks can miss that window. This retry guarantees we don't.
512	      let attempts = 0;
513	      const attempt = () => {
514	        const placed = ensureInjected();
515	        // Show the floating fallback only after a short grace period, so on a
516	        // normally-rendering surface the native button just appears — no flash
517	        // of the FAB getting replaced a moment later.
518	        fab.setVisible(allowFab && !placed && attempts >= 3);
519	        if (placed || attempts++ >= 30) return;
520	        retryTimer = setTimeout(attempt, 150);
521	      };
522	      attempt();
523	    },
524	  };
525	}
526	
527	/**
528	 * Is this open `[role="dialog"]` an actual event surface (detail popover / quick
529	 * edit), rather than one of Google's transient confirmation dialogs — e.g.
530	 * "Send update emails to existing Google Calendar guests?" or "Delete this
531	 * event?" — which we must not decorate? Positive, stable signals only: an event
532	 * chip id, the magic address in its text, or several icon-led section rows
533	 * (time / guests / location). A confirmation dialog is just a question plus a
534	 * row of action buttons, so it matches none of these.
535	 */
536	function isEventDialog(dialog: HTMLElement): boolean {
