/**
 * Resolve a guest's real name from the host's Google Contacts via the People API.
 *
 * Why: Google omits `attendee.displayName` for external non-contact guests — the
 * name shown in the Calendar UI is resolved client-side from the host's contacts
 * and never reaches the event API. This replicates that lookup server-side: given
 * the host's OAuth client, search their contacts (and "other contacts" they've
 * interacted with) for the attendee email and return the saved name.
 *
 * Requires contacts.readonly + contacts.other.readonly scopes (host must reconnect
 * to grant them) and the People API enabled in the GCP project. Only works when the
 * email is actually a saved/interacted contact — fails gracefully otherwise.
 */

import { google } from 'googleapis';

type PeopleAuth = InstanceType<typeof google.auth.OAuth2>;

// Process-level caches. The search APIs need a one-time "warmup" (empty query)
// before they return results, so we prime each client once.
const warmedClients = new WeakSet<object>();
const nameCache = new Map<string, string | null>(); // email → name (null = looked up, not found)

export async function resolveNameFromContacts(auth: PeopleAuth, email: string): Promise<string | undefined> {
  const key = email.toLowerCase();
  const cached = nameCache.get(key);
  if (cached !== undefined) return cached ?? undefined;

  const people = google.people({ version: 'v1', auth });

  if (!warmedClients.has(auth)) {
    warmedClients.add(auth);
    // Warmup — Google requires a prior request to prime the search cache.
    await people.people.searchContacts({ query: '', readMask: 'names,emailAddresses' }).catch(() => {});
    await people.otherContacts.search({ query: '', readMask: 'names,emailAddresses' }).catch(() => {});
  }

  const name =
    (await searchContacts(people, email)) ??
    (await searchOtherContacts(people, email));

  nameCache.set(key, name ?? null);
  return name;
}

function pickName(person: { names?: { displayName?: string | null }[] | null; emailAddresses?: { value?: string | null }[] | null } | undefined, email: string): string | undefined {
  if (!person) return undefined;
  const emails = person.emailAddresses ?? [];
  if (!emails.some((e) => e.value?.toLowerCase() === email.toLowerCase())) return undefined;
  return person.names?.[0]?.displayName ?? undefined;
}

async function searchContacts(people: ReturnType<typeof google.people>, email: string): Promise<string | undefined> {
  try {
    const res = await people.people.searchContacts({ query: email, readMask: 'names,emailAddresses', pageSize: 10 });
    for (const r of res.data.results ?? []) {
      const name = pickName(r.person ?? undefined, email);
      if (name) return name;
    }
  } catch (err: any) {
    console.warn(`[CalendarContacts] searchContacts failed for ${email}:`, err?.response?.data?.error?.message ?? err?.message ?? err);
  }
  return undefined;
}

async function searchOtherContacts(people: ReturnType<typeof google.people>, email: string): Promise<string | undefined> {
  try {
    const res = await people.otherContacts.search({ query: email, readMask: 'names,emailAddresses', pageSize: 10 });
    for (const r of res.data.results ?? []) {
      const name = pickName(r.person ?? undefined, email);
      if (name) return name;
    }
  } catch (err: any) {
    console.warn(`[CalendarContacts] otherContacts.search failed for ${email}:`, err?.response?.data?.error?.message ?? err?.message ?? err);
  }
  return undefined;
}

