/**
 * Build the curated roster from raw attendees: drop the host + blanks, dedup
 * case-insensitively, derive a name when absent, pre-fill phone via `phoneLookup`,
 * and set each guest's DEFAULT toggle via `includeDecider` (so same-workspace /
 * same-location colleagues come pre-toggled-OFF — same rule as every other channel).
 * Pure (DB + classification injected) → unit-testable.
 */
export async function buildRoster(
  attendees: { email: string; name?: string }[],
  hostEmail: string | undefined,
  phoneLookup: PhoneLookup,
  includeDecider: IncludeDecider = () => true,
): Promise<DraftGuest[]> {
  const host = hostEmail?.toLowerCase();
  const seen = new Set<string>();
  const roster: DraftGuest[] = [];
  for (const attendee of attendees) {
    const email = attendee.email?.toLowerCase();
    if (!email || email === host || seen.has(email)) continue;
    seen.add(email);
    const include = includeDecider(email);
    roster.push({
      email,
      name: attendee.name?.trim() || nameFromEmail(email),
      phone: await phoneLookup(email),
      include,
      // Default-off ⟺ internal same/unknown-office colleague (external and
      // different-office guests are always default-on). A display hint for the card.
      internal: !include,
      status: 'pending',
    });
  }
  return roster;
}

