1	import { useEffect, useState } from 'react';
2	import {
3	  useMutation,
4	  useQuery,
5	  useQueryClient,
6	} from '@tanstack/react-query';
7	import { ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY, rpc } from '@/lib/messaging';
8	import type {
9	  ActiveEvent,
10	  AuthStatus,
11	  DomEventSnapshot,
12	  DraftPatch,
13	  DraftResponse,
14	  VisitDraft,
15	} from '@/lib/types';
16	
17	/** The pending event id, read reactively from storage.session. */
18	export function useActiveEid(): string | null {
19	  const [eid, setEid] = useState<string | null>(null);
20	  useEffect(() => {
21	    chrome.storage.session
22	      .get(ACTIVE_EID_KEY)
23	      .then((r) => setEid((r[ACTIVE_EID_KEY] as string) ?? null));
24	    const listener = (
25	      changes: { [k: string]: chrome.storage.StorageChange },
26	      area: string,
27	    ) => {
28	      if (area === 'session' && changes[ACTIVE_EID_KEY]) {
29	        setEid((changes[ACTIVE_EID_KEY].newValue as string) ?? null);
30	      }
31	    };
32	    chrome.storage.onChanged.addListener(listener);
33	    return () => chrome.storage.onChanged.removeListener(listener);
34	  }, []);
35	  return eid;
36	}
37	
38	/** The DOM snapshot for the active event (instant + unsaved fallback). */
39	export function useActiveSnapshot(): DomEventSnapshot | null {
40	  const [snap, setSnap] = useState<DomEventSnapshot | null>(null);
41	  useEffect(() => {
42	    chrome.storage.session
43	      .get(ACTIVE_SNAPSHOT_KEY)
44	      .then((r) => setSnap((r[ACTIVE_SNAPSHOT_KEY] as DomEventSnapshot) ?? null));
45	    const listener = (
46	      changes: { [k: string]: chrome.storage.StorageChange },
47	      area: string,
48	    ) => {
49	      if (area === 'session' && changes[ACTIVE_SNAPSHOT_KEY]) {
50	        setSnap((changes[ACTIVE_SNAPSHOT_KEY].newValue as DomEventSnapshot) ?? null);
51	      }
52	    };
53	    chrome.storage.onChanged.addListener(listener);
54	    return () => chrome.storage.onChanged.removeListener(listener);
55	  }, []);
56	  return snap;
57	}
58	
59	export function useAuthStatus() {
60	  return useQuery({
61	    queryKey: ['auth'],
62	    queryFn: () => rpc({ type: 'AUTH_STATUS' }),
63	  });
64	}
65	
66	export function useSignIn() {
67	  const qc = useQueryClient();
68	  return useMutation({
69	    mutationFn: () => rpc({ type: 'AUTH_SIGN_IN' }),
70	    onSuccess: (status: AuthStatus) => {
71	      qc.setQueryData(['auth'], status);
72	      // re-run any failed queries now that we're signed in
73	      qc.invalidateQueries();
74	    },
75	  });
76	}
77	
78	export function useSignOut() {
79	  const qc = useQueryClient();
80	  return useMutation({
81	    mutationFn: () => rpc({ type: 'AUTH_SIGN_OUT' }),
82	    onSuccess: () => {
83	      qc.setQueryData(['auth'], { signedIn: false });
84	      // Drop draft/resolve caches so the panel re-gates to sign-in.
85	      qc.removeQueries({ queryKey: ['draft'] });
86	      qc.removeQueries({ queryKey: ['resolve'] });
87	    },
88	  });
89	}
90	
91	export function useResolveEvent(eid: string | null) {
92	  return useQuery({
93	    queryKey: ['resolve', eid],
94	    queryFn: () => rpc({ type: 'RESOLVE_EVENT', eid: eid! }),
95	    enabled: !!eid,
96	    staleTime: 60_000,
97	  });
98	}
99	
100	export function useDraft(event: ActiveEvent | undefined) {
101	  return useQuery({
102	    queryKey: ['draft', event?.iCalUid],
103	    queryFn: () => rpc({ type: 'DRAFT_LOAD', event: event! }),
104	    enabled: !!event?.iCalUid,
105	  });
106	}
107	
108	/** Merge a returned VisitDraft into the cached DraftResponse (keep extras). */
109	function mergeDraft(
110	  prev: DraftResponse | undefined,
111	  next: VisitDraft,
112	): DraftResponse | undefined {
113	  if (!prev) return prev;
114	  return { ...prev, ...next };
115	}
116	
117	/** Optimistic patch (toggle / name / phone / template / location). */
118	export function usePatchDraft(iCalUid: string | undefined) {
119	  const qc = useQueryClient();
120	  const key = ['draft', iCalUid];
121	  return useMutation({
122	    mutationFn: (patch: DraftPatch) =>
123	      rpc({ type: 'DRAFT_PATCH', iCalUid: iCalUid!, patch }),
124	    onMutate: async (patch) => {
125	      await qc.cancelQueries({ queryKey: key });
126	      const prev = qc.getQueryData<DraftResponse>(key);
127	      if (prev) qc.setQueryData<DraftResponse>(key, applyPatch(prev, patch));
128	      return { prev };
129	    },
130	    onError: (_e, _patch, ctx) => {
131	      if (ctx?.prev) qc.setQueryData(key, ctx.prev);
132	    },
133	    onSuccess: (updated) => {
134	      qc.setQueryData<DraftResponse>(key, (prev) => mergeDraft(prev, updated));
135	    },
136	  });
137	}
138	
139	/** Apply a DraftPatch to a cached DraftResponse for the optimistic view. */
140	function applyPatch(draft: DraftResponse, patch: DraftPatch): DraftResponse {
141	  const roster = draft.roster.map((g) => {
142	    const edit = patch.guests?.find(
143	      (e) => e.email.toLowerCase() === g.email.toLowerCase(),
144	    );
145	    return edit ? { ...g, ...stripEmail(edit) } : g;
146	  });
147	  return {
148	    ...draft,
149	    roster,
150	    location: patch.location ?? draft.location,
151	  };
152	}
153	
154	function stripEmail<T extends { email: string }>(e: T): Omit<T, 'email'> {
155	  const { email: _email, ...rest } = e;
156	  return rest;
157	}
158	
159	export function useSend(iCalUid: string | undefined, start?: string, end?: string) {
160	  const qc = useQueryClient();
161	  return useMutation({
162	    mutationFn: () => rpc({ type: 'SEND', iCalUid: iCalUid!, start, end }),
163	    onSuccess: (res) => {
164	      qc.setQueryData<DraftResponse>(['draft', iCalUid], (prev) =>
165	        mergeDraft(prev, res.draft),
166	      );
167	    },
168	  });
169	}
170	
171	export function usePreview(iCalUid: string | undefined) {
172	  return useMutation({
173	    mutationFn: (visitorEmail: string) =>
174	      rpc({ type: 'PREVIEW', iCalUid: iCalUid!, visitorEmail }),
175	  });
176	}
177	
178	/** Upcoming visitor events (the synced magic-address set) for the picker. */
179	export function useVisitorEvents(enabled: boolean) {
180	  return useQuery({
