1	/**
2	 * Per-user Google Calendar OAuth — connect flow + connection store.
3	 *
4	 * Canonical design: Planning-docs/2026-06-12_calendar_to_visitor_invite_research.md §8.
5	 *
6	 * A host connects once (one tap from the Slack App Home / first-DM button). We store
7	 * a long-lived refresh token in `calendar_connections`, then `calendar-sync.ts` polls
8	 * their calendar and feeds events into `ingestCalendarEvent` as source 'oauth'.
9	 *
10	 * Reuses the admin-SSO OAuth client credentials (GOOGLE_OAUTH_*) — fine for
11	 * internal-first (each flow requests only its own scopes; that client already
12	 * carried calendar-read). Scope is a single `calendar.events` (read+write):
13	 * read powers the lifecycle watch (move/delete of tracked events); write powers
14	 * creating the event on a Slack-self-host's calendar (D8). calendar.events is
15	 * "sensitive", NOT restricted → still no CASA. Never add Gmail/Drive.
16	 *
17	 * For a non-expiring refresh token the OAuth app must be "In production" (Testing =
18	 * 7-day expiry). See research doc §8.
19	 */
20	
21	import { createHmac, timingSafeEqual } from 'crypto';
22	import { google } from 'googleapis';
23	import { getDb } from '../../lib/database';
24	import { googleOauth as googleOauthConfig, auxilioExtensionOauth } from '../../lib/config';
25	
26	const STATE_TTL_MS = 15 * 60 * 1000;
27	const DEFAULT_TENANT_ID = 'appointy';
28	
29	/**
30	 * Single scope: calendar.events (READ+WRITE). Read = the lifecycle watch; write =
31	 * creating the event on a Slack-self-host's calendar (D8, so it's trackable + the
32	 * guest is invited natively). "Sensitive", NOT restricted → no CASA. Contacts were
33	 * dropped: name resolution lives in the add-on (its own People API) + the invite
34	 * forms; the poll no longer creates invites, so backend contacts is dead. Never
35	 * add Gmail/Drive here.
36	 */
37	const CALENDAR_SCOPES = [
38	  'https://www.googleapis.com/auth/calendar.events',
39	];
40	
41	/**
42	 * Bump whenever CALENDAR_SCOPES changes. NOTE: this does NOT force a reconnect —
43	 * `listScopeStaleConnections` only *flags* older-version connections (their token
44	 * still covers calendar-read, so the watch keeps working). We prompt the write
45	 * upgrade lazily (only when a Slack host needs to create an event). Connections at
46	 * this version are write-capable (`calendar.events`); older ones are read-only.
47	 */
48	export const CURRENT_SCOPE_VERSION = 'v3-events-rw';
49	
50	/**
51	 * Scope marker for connections created by the Chrome extension sign-in. Readonly
52	 * (`calendar.events.readonly`) — enough for the poll + watch, never write-capable.
53	 * Kept distinct so isWriteCapableConnection stays false and the Slack reconnect
54	 * nudge (listScopeStaleConnections) skips these.
55	 */
56	export const EXTENSION_SCOPE_VERSION = 'v-ext-events-ro';
57	
58	/**
59	 * A connection can CREATE calendar events (write) once it's been granted the
60	 * current `calendar.events` scope. Older read-only connections return false →
61	 * the Slack create-from-form flow prompts a lazy reconnect instead of writing.
62	 */
63	export function isWriteCapableConnection(conn: { scope_version?: string | null } | null | undefined): boolean {
64	  return conn?.scope_version === CURRENT_SCOPE_VERSION;
65	}
66	
67	/** True when the host has a live, write-capable connection (can create events via OAuth). */
68	export async function isHostWriteCapable(hostEmail: string): Promise<boolean> {
69	  const conn = await getCalendarConnection(hostEmail).catch(() => null);
70	  return !!conn && conn.status === 'connected' && !!conn.refresh_token && isWriteCapableConnection(conn);
71	}
72	
73	function stateSecret(): string {
74	  return process.env.VISITOR_ADMIN_SESSION_SECRET
75	    ?? process.env.VISITOR_ADMIN_SECRET
76	    ?? 'calendar-oauth-state-fallback';
77	}
78	
79	export function isCalendarOAuthConfigured(): boolean {
80	  return !!(googleOauthConfig.clientId() && googleOauthConfig.clientSecret() && googleOauthConfig.publicOrigin());
81	}
82	
83	export function isAuxilioExtensionOAuthConfigured(): boolean {
84	  return !!(auxilioExtensionOauth.clientId() && auxilioExtensionOauth.clientSecret());
85	}
86	
87	function callbackUrl(): string {
88	  const origin = (googleOauthConfig.publicOrigin() ?? '').replace(/\/$/, '');
89	  if (!origin) throw new Error('GOOGLE_OAUTH_PUBLIC_ORIGIN is not configured');
90	  return `${origin}/api/visitor/calendar/connect/callback`;
91	}
92	
93	function buildClient() {
94	  const clientId = googleOauthConfig.clientId();
95	  const clientSecret = googleOauthConfig.clientSecret();
96	  if (!clientId || !clientSecret) throw new Error('Google OAuth client credentials are not configured');
97	  return new google.auth.OAuth2(clientId, clientSecret, callbackUrl());
98	}
99	
100	// ─── Signed state (carries host binding, no server-side store) ────────
101	
102	export interface CalendarStatePayload {
103	  email: string;
104	  slackUserId?: string;
105	}
106	
107	export function issueCalendarState(payload: CalendarStatePayload): string {
108	  const body = Buffer.from(JSON.stringify({ ...payload, exp: Date.now() + STATE_TTL_MS })).toString('base64url');
109	  const sig = createHmac('sha256', stateSecret()).update(body).digest('base64url');
110	  return `${body}.${sig}`;

