1	import {
2	  ACTIVE_EID_KEY,
3	  ACTIVE_SNAPSHOT_KEY,
4	  AUTH_LAPSED,
5	  NUDGE_TARGETS,
6	  PANEL_STATE,
7	  SIDEPANEL_PORT,
8	  broadcastRefreshActive,
9	  type RpcRequest,
10	  type RpcResponse,
11	} from '@/lib/messaging';
12	import { authStatus, getValidTokens, signIn, signOut, wasConnected } from '@/lib/auth';
13	import { decodeEid, encodeEid, fetchActiveEvent } from '@/lib/calendar';
14	import {
15	  clearSyncToken,
16	  listMarked,
17	  listPendingICalUids,
18	  markHandled,
19	  readEngineHandled,
20	  runSync,
21	  setEngineHandled,
22	} from '@/lib/calendar-sync';
23	import { EngineError, engine } from '@/lib/engine';
24	import type { VisitorEventSummary } from '@/lib/types';
25	
26	const SYNC_ALARM = 'auxilio-sync';
27	const BADGE_COLOR = '#92288E';
28	// Cross-channel status poll throttle: don't ask the engine "which are handled"
29	// every alarm tick. Poll when the pending iCalUid set changes, else at most this
30	// often. Stored in storage.local so the throttle survives SW restarts.
31	const STATUS_POLL_KEY = 'auxilio.statusPoll';
32	const STATUS_POLL_INTERVAL_MS = 5 * 60_000;
33	// Muted/error badge for a recoverable auth lapse — visually distinct from the
34	// brand-tinted visitor-count badge so "nudging is offline" never reads as a count.
35	const LAPSED_BADGE_COLOR = '#B3261E';
36	
37	// Whether the side panel is currently open (a port is connected). Content
38	// scripts ask for this on (re)load so auto-follow works after navigation.
39	let panelConnected = false;
40	
41	export default defineBackground(() => {
42	  // Let content scripts read/write storage.session (default is trusted-only).
43	  // Needed for the active-event handoff + nudge-dismissal persistence.
44	  chrome.storage.session
45	    .setAccessLevel({ accessLevel: 'TRUSTED_AND_UNTRUSTED_CONTEXTS' })
46	    .catch((err) => console.warn('[auxilio] setAccessLevel failed', err));
47	
48	  // Toolbar icon opens the panel (Chrome's required user gesture).
49	  chrome.sidePanel
50	    .setPanelBehavior({ openPanelOnActionClick: true })
51	    .catch((err) => console.error('[auxilio] setPanelBehavior failed', err));
52	
53	  // Durable, official change-detection: poll on an alarm (no DOM).
54	  chrome.alarms.create(SYNC_ALARM, { periodInMinutes: 1 });
55	  chrome.runtime.onInstalled.addListener(() => {
56	    chrome.alarms.create(SYNC_ALARM, { periodInMinutes: 1 });
57	    // Re-scan from scratch on install/update: a config change (e.g. the magic
58	    // address) only takes effect on a full sync, since incremental never
59	    // re-reports an already-consumed change. clearSyncToken forces that.
60	    void clearSyncToken().then(() => doSync());
61	  });
62	  chrome.runtime.onStartup.addListener(() => void doSync());
63	  chrome.alarms.onAlarm.addListener((a) => {
64	    if (a.name === SYNC_ALARM) void doSync();
65	  });
66	  chrome.notifications.onClicked.addListener((id) => chrome.notifications.clear(id));
67	
68	  // Track the side panel open/closed via a port it connects on mount, and tell
69	  // calendar tabs so the in-page button can hide while the panel is open.
70	  chrome.runtime.onConnect.addListener((port) => {
71	    if (port.name !== SIDEPANEL_PORT) return;
72	    panelConnected = true;
73	    broadcastPanelState(true);
74	    port.onDisconnect.addListener(() => {
75	      panelConnected = false;
76	      broadcastPanelState(false);
77	    });
78	  });
79	
80	  chrome.runtime.onMessage.addListener((msg: RpcRequest, sender, sendResponse) => {
81	    if (typeof msg?.type === 'string' && msg.type.startsWith('__')) return false; // broadcasts
82	    handle(msg, sender)
83	      .then(sendResponse)
84	      .catch((err) => sendResponse(fail(err)));
85	    return true; // async response
86	  });
87	
88	  console.log('[auxilio] background ready');
89	});
90	
91	// ─────────────────────────── sync loop ───────────────────────────
92	
93	async function doSync(): Promise<void> {
94	  let tokens: { idToken: string; accessToken: string };
95	  try {
96	    tokens = await getValidTokens();
97	  } catch {
98	    // Token unavailable. If the user was connected, this is a recoverable lapse
99	    // (storage.session wiped on restart, or silent renew failed) — surface it so
100	    // nudging never dies silently. If they never connected, stay quiet.
101	    if (await wasConnected()) await setLapsed(true);
102	    return;
103	  }
104	  let result;
105	  try {
106	    result = await runSync(tokens.accessToken);
107	  } catch (err) {
108	    console.warn('[auxilio] sync failed', err);
109	    return;
110	  }
111	
112	  // Got here with working tokens → any prior lapse is over.
113	  await setLapsed(false);
114	
115	  // Cross-channel suppression: ask the engine which marked events already have an
116	  // active pass (issued via the add-on or another device), so we don't nag for
117	  // them. Gated/throttled so this isn't a per-minute engine call.
118	  const engineHandled = await maybePollEngineStatus(tokens.idToken);
119	
120	  // Toolbar badge = distinct visitor events still needing passes (engine-filtered,
121	  // series-collapsed) — sourced from listMarked so it matches the banner exactly.
122	  const targets = await listMarked();
123	  await chrome.action.setBadgeBackgroundColor({ color: BADGE_COLOR });
124	  await chrome.action.setBadgeText({ text: targets.length > 0 ? String(targets.length) : '' });
125	
126	  // OS notification for each newly-discovered visitor event (out-of-tab alert) —
127	  // but never for one the engine has already handled elsewhere.
128	  for (const ev of result.newMarked) {
129	    if (!engineHandled.has((ev.iCalUid ?? '').toLowerCase())) notifyVisitorEvent(ev);
130	  }
131	
132	  // In-page nudge banner: push the current marked set to calendar tabs, plus
133	  // any events that just stopped being pending (deleted/cancelled) so the page
134	  // can purge stale optimistic nudges for them.
135	  broadcastNudge(targets, result.cancelledIds);
136	
137	  // If the event the panel is showing changed (post-save), tell it to refetch.
138	  const stored = await chrome.storage.session.get(ACTIVE_EID_KEY);
139	  const activeEid = stored[ACTIVE_EID_KEY] as string | undefined;
140	  if (activeEid) {
141	    const dec = decodeEid(activeEid);
142	    if (dec && result.changedIds.has(dec.eventId)) broadcastRefreshActive();
143	  }
144	}
145	
146	/** Ask the engine which pending events already have an active pass (handled via
147	 *  any surface), and cache the answer. Throttled: re-polls when the pending set
148	 *  changes, else at most every STATUS_POLL_INTERVAL_MS. Degrades gracefully — if
149	 *  the engine/route is unreachable it keeps the last known set (local-only
150	 *  suppression still works). Returns the (lower-cased) engine-handled set. */
151	async function maybePollEngineStatus(idToken: string): Promise<Set<string>> {
152	  const uids = await listPendingICalUids();
153	  if (uids.length === 0) {
154	    await setEngineHandled([]); // nothing pending → clear the cache
155	    return new Set();
156	  }
157	  const sig = [...uids].sort().join('|');
158	  const store = await chrome.storage.local.get(STATUS_POLL_KEY);
159	  const last = store[STATUS_POLL_KEY] as { at: number; sig: string } | undefined;
160	  const fresh = last && Date.now() - last.at < STATUS_POLL_INTERVAL_MS;
161	  if (last && last.sig === sig && fresh) return readEngineHandled(); // reuse cache
162	
163	  // Stamp the throttle now (before the call) so a missing/erroring route backs off
164	  // instead of retrying every tick. A changed signature still forces a re-poll.
165	  await chrome.storage.local.set({ [STATUS_POLL_KEY]: { at: Date.now(), sig } });
166	  try {
167	    const { active } = await engine.status(idToken, uids);
168	    await setEngineHandled(active);
169	    return new Set(active.map((u) => u.toLowerCase()));
170	  } catch (err) {
171	    console.warn('[auxilio] engine status poll failed; keeping last known', err);
172	    return readEngineHandled();
173	  }
174	}
175	
176	function broadcastPanelState(open: boolean): void {
177	  sendToCalendarTabs({ type: PANEL_STATE, open });
178	}
179	
180	function broadcastNudge(targets: VisitorEventSummary[], cancelled: string[] = []): void {
181	  sendToCalendarTabs({ type: NUDGE_TARGETS, targets, cancelled });
182	}
183	
184	/** Enter/leave the recoverable auth-lapsed state: a distinct toolbar badge plus a
185	 *  broadcast that drives the in-page "Reconnect" banner. Broadcast unconditionally
186	 *  so a calendar tab loaded mid-lapse learns about it on the next sync. */
187	async function setLapsed(lapsed: boolean): Promise<void> {
188	  if (lapsed) {
189	    await chrome.action.setBadgeBackgroundColor({ color: LAPSED_BADGE_COLOR });
190	    await chrome.action.setBadgeText({ text: '!' });
191	  }
192	  sendToCalendarTabs({ type: AUTH_LAPSED, lapsed });
193	}
194	
195	/** Recompute the nudge surfaces from local state (no Calendar round-trip) — used
196	 *  after a send marks an event handled, so the badge/banner drop it immediately. */
197	async function refreshNudgeSurfaces(): Promise<void> {
198	  const targets = await listMarked();
199	  await chrome.action.setBadgeBackgroundColor({ color: BADGE_COLOR });
200	  await chrome.action.setBadgeText({ text: targets.length > 0 ? String(targets.length) : '' });
201	  broadcastNudge(targets);
202	}
203	
204	function sendToCalendarTabs(message: unknown): void {
205	  chrome.tabs
206	    .query({ url: 'https://calendar.google.com/*' })
207	    .then((tabs) => {
208	      for (const t of tabs) {
209	        if (t.id != null) chrome.tabs.sendMessage(t.id, message).catch(() => {});
210	      }
211	    })
212	    .catch(() => {});
213	}
214	
215	function notifyVisitorEvent(ev: VisitorEventSummary): void {
216	  chrome.notifications.create(`auxilio:${ev.eventId}`, {
217	    type: 'basic',
218	    iconUrl: chrome.runtime.getURL('icon/128.png'),
219	    title: 'Visitor event',
220	    message: `${ev.title}. Open Auxilio to register passes.`,
221	    priority: 1,
222	  });
223	}
224	
225	// ─────────────────────────── RPC plumbing ───────────────────────────
226	
227	const ok = <T,>(data: T): RpcResponse<T> => ({ ok: true, data });
228	
229	function fail(err: unknown): RpcResponse<never> {
230	  const message = err instanceof Error ? err.message : String(err);
231	  const status = err instanceof EngineError ? err.status : undefined;
232	  return { ok: false, error: message, status, needsAuth: status === 401 };
233	}
234	
235	async function withTokens<T>(
236	  fn: (t: { idToken: string; accessToken: string; email?: string }) => Promise<T>,
237	): Promise<RpcResponse<T>> {
238	  let tokens;
239	  try {
240	    tokens = await getValidTokens();
241	  } catch {
242	    return { ok: false, error: 'Sign in to continue.', needsAuth: true };
243	  }
244	  try {
245	    return ok(await fn(tokens));
246	  } catch (err) {
247	    return fail(err);
248	  }
249	}
250	
251	const withIdToken = <T,>(fn: (idToken: string) => Promise<T>) =>
252	  withTokens((t) => fn(t.idToken));
253	
254	async function handle(
255	  msg: RpcRequest,
256	  sender: chrome.runtime.MessageSender,
257	): Promise<RpcResponse<unknown>> {
258	  switch (msg.type) {
259	    case 'AUTH_STATUS':
260	      return ok(await authStatus());
261	    case 'AUTH_SIGN_IN': {
262	      const status = await signIn();
263	      void doSync(); // warm the marked set + badge right after sign-in
264	      return ok(status);
265	    }
266	    case 'AUTH_SIGN_OUT':
267	      await signOut();
268	      await chrome.action.setBadgeText({ text: '' });
269	      return ok({ signedIn: false });
270	
271	    case 'OPEN_PANEL': {
272	      // Open the side panel within the in-page click's user activation (e.g. the
273	      // "Reconnect" banner) so the user lands on the sign-in gate. No active event.
274	      const tabId = sender.tab?.id;
275	      let opened = false;
276	      if (!panelConnected && tabId != null) {
277	        try {
278	          await chrome.sidePanel.open({ tabId });
279	          opened = true;
280	        } catch (err) {
281	          console.warn('[auxilio] sidePanel.open failed (gesture not carried?)', err);
282	        }
283	      }
284	      return ok({ opened });
285	    }
286	
287	    case 'OPEN_FOR_EVENT': {
