26	  rpc,
27	} from '@/lib/messaging';
28	import type { PreviewResponse } from '@/lib/types';
29	import {
30	  useActiveEid,
31	  useActiveSnapshot,
32	  useAuthStatus,
33	  useDraft,
34	  usePatchDraft,
35	  usePreview,
36	  useResolveEvent,
37	  useSend,
38	  useVisitorEvents,
39	} from './hooks';
40	import { AccountMenu } from './AccountMenu';
41	import { EmptyState } from './EmptyState';
42	import { RosterRow } from './RosterRow';
43	import { PreviewSheet } from './PreviewSheet';
44	import { SignInGate } from './SignInGate';
45	
46	const isAuthError = (err: unknown) => err instanceof RpcError && !!err.needsAuth;
47	
48	export function VisitPanel() {
49	  // `storedEid` is what the content script is pointing us at (auto-follow). We
50	  // freeze the *displayed* `eid` while busy so following never switches the view
51	  // mid-action (Guard 1); edits already persist on blur (Guard 2).
52	  const storedEid = useActiveEid();
53	  const snapshot = useActiveSnapshot();
54	  const [eid, setEid] = useState<string | null>(storedEid);
55	  const auth = useAuthStatus();
56	  // Picker fuels the "open from list" empty state (and graceful fallback).
57	  const visitorEvents = useVisitorEvents(!eid && !!auth.data?.signedIn);
58	  const resolve = useResolveEvent(eid);
59	  const event = resolve.data;
60	  const draft = useDraft(event);
61	
62	  const patch = usePatchDraft(event?.iCalUid);
63	  const send = useSend(event?.iCalUid, event?.start, event?.end);
64	  const preview = usePreview(event?.iCalUid);
65	
66	  const [previewData, setPreviewData] = useState<{
67	    preview: PreviewResponse;
68	    recipient: string;
69	  } | null>(null);
70	  // Tracks host edits the roster can't otherwise reveal — a name/phone change or
71	  // template switch on an already-issued event leaves no structural delta, so we
72	  // remember "the host touched something" to keep the update button live. Reset
73	  // when the event changes or a send succeeds (the draft then reflects reality).
74	  const [edited, setEdited] = useState(false);
75	  useEffect(() => setEdited(false), [event?.iCalUid]);
76	
77	  // Guard 1: hold the current event while sending / previewing; catch up once idle.
78	  const busy = send.isPending || preview.isPending || !!previewData;
79	  useEffect(() => {
80	    if (!busy) setEid(storedEid);
81	  }, [storedEid, busy]);
82	
83	  // Post-save refresh: the background sync poll broadcasts when the active event
84	  // changed on the server (no DOM); refetch so the roster reflects saved state.
85	  const qc = useQueryClient();
86	  useEffect(() => {
87	    const listener = (msg: { type?: string }) => {
88	      if (msg?.type === REFRESH_ACTIVE) {
89	        qc.invalidateQueries({ queryKey: ['resolve'] });
90	        qc.invalidateQueries({ queryKey: ['draft'] });
91	      }
92	    };
93	    chrome.runtime.onMessage.addListener(listener);
94	    return () => chrome.runtime.onMessage.removeListener(listener);
95	  }, [qc]);
96	
97	  // Back → clear the active event/snapshot, returning to the home list.
98	  const clearActive = () =>
99	    chrome.storage.session.remove([ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY]);
100	  // Show Back in every screen except the pure home (no event, no snapshot).
101	  const back = eid || snapshot?.magicPresent ? clearActive : undefined;
102	
103	  // ---- gating states ----
104	  if (!eid) {
105	    // New, not-yet-saved visitor event (no eid, but the DOM saw the magic
106	    // address) → preview the detected guests + prompt to save.
107	    if (snapshot?.magicPresent) {
108	      return (
109	        <Shell onBack={back}>
110	          <NoticeState
111	            title="Save the event to issue passes"
112	            body="This event isn’t saved yet, so passes can’t be issued. Add your guests and save it in Google Calendar, then reopen Manage Visitors."
113	            guests={snapshot.guestEmails}
114	          />
115	        </Shell>
116	      );
117	    }
118	    return (
119	      <Shell>
120	        <EmptyState
121	          auth={auth.data}
122	          events={visitorEvents.data}
123	          loading={visitorEvents.isLoading}
124	          onPick={(ev) => {
125	            // Just point the panel at the picked event — no tab navigation. Use
126	            // "Open in Calendar" in the summary to jump to it explicitly.
127	            chrome.storage.session.set({ [ACTIVE_EID_KEY]: ev.eid });
128	          }}
129	        />
130	      </Shell>
131	    );
132	  }
133	  if (isAuthError(resolve.error) || isAuthError(draft.error)) {
134	    return <Shell onBack={back}><SignInGate /></Shell>;
135	  }
136	  if (resolve.isLoading) return <Shell onBack={back}><LoadingState label="Reading event…" /></Shell>;
137	  if (resolve.isError) {
138	    const msg = (resolve.error as Error).message;
139	    if (msg === 'NOT_SAVED') {
140	      return (
141	        <Shell onBack={back}>
142	          <NoticeState
143	            title="Save the event to issue passes"
144	            body="This event isn’t saved yet, so passes can’t be issued. Save it in Google Calendar, then reopen Manage Visitors."
145	            onRetry={() => resolve.refetch()}
146	            guests={snapshot?.guestEmails}
147	          />
148	        </Shell>
149	      );
150	    }
151	    return (
152	      <Shell onBack={back}>
153	        <ErrorState message={msg} onRetry={() => resolve.refetch()} />
154	      </Shell>
155	    );
156	  }
157	  // Event resolved but no iCalUID → the draft query can't run (would sit on a
158	  // skeleton forever). Surface it instead of hanging.
159	  if (event && !event.iCalUid) {
160	    return (
161	      <Shell onBack={back}>
162	        <NoticeState
163	          title="Can’t register from this event"
164	          body="This event has no calendar UID yet. This usually means it is not fully saved. Save it in Google Calendar and try again."
165	          onRetry={() => resolve.refetch()}
166	        />
167	      </Shell>
168	    );
169	  }
170	  if (draft.isError) {
171	    return (
172	      <Shell onBack={back}>
173	        <ErrorState message={(draft.error as Error).message} onRetry={() => draft.refetch()} />
174	      </Shell>
175	    );
176	  }
177	  if (!draft.data) {
178	    return <Shell onBack={back}><RosterSkeleton title={event?.title} /></Shell>;
179	  }
180	
181	  const data = draft.data;
182	  const included = data.roster.filter((g) => g.include);
183	  const sentCount = data.roster.filter((g) => g.status === 'sent').length;
184	
185	  // What's actually pending. A new/uninvited guest still to get a pass, or a sent
186	  // guest toggled off (a pending revoke), is a structural change visible in the
187	  // roster. Name/phone/template edits aren't — `edited` covers those.
188	  const pendingNew = data.roster.filter(
189	    (g) => g.include && g.status !== 'sent' && g.status !== 'cancelled',
190	  );
191	  const pendingCancel = data.roster.filter((g) => g.status === 'sent' && !g.include);
192	  const hasChanges = pendingNew.length > 0 || pendingCancel.length > 0 || edited;
193	  // Already-issued event with literally nothing to do → no point re-sending.
194	  const nothingToDo = data.materialized && !hasChanges;
195	
196	  const templates = data.emailTemplates;
197	  // One template for the whole event (engine stores per-guest; we set all guests
198	  // to the chosen key).
199	  const currentTemplate =
200	    data.roster.find((g) => g.emailTemplateKey)?.emailTemplateKey ??
201	    templates.find((t) => t.isDefault)?.key ??
202	    templates[0]?.key;
203	
204	  const patchGuest = (email: string, edit: Record<string, unknown>) => {
205	    setEdited(true);
206	    patch.mutate({ guests: [{ email, ...edit }] });
207	  };
208	
209	  const setEventTemplate = (key: string) => {
210	    setEdited(true);
211	    patch.mutate({ guests: data.roster.map((g) => ({ email: g.email, emailTemplateKey: key })) });
212	  };
213	
214	  // Review & send: render the real email for a representative included guest,
215	  // then Send/Cancel from the preview.
216	  const reviewEmail = included[0]?.email;
217	  const openReview = () => {
218	    if (!reviewEmail) return;
219	    preview.mutate(reviewEmail, {
220	      onSuccess: (d) => setPreviewData({ preview: d, recipient: reviewEmail }),
221	    });
222	  };
223	
224	  // First send needs at least one included guest; an already-issued event needs a
225	  // real pending change — otherwise the button is irrelevant and stays disabled.
226	  const canSend =
227	    !send.isPending && (data.materialized ? hasChanges : included.length > 0);
228	  const reviewLabel = data.materialized ? 'Review & update passes' : 'Review & send passes';
229	
230	  return (
231	    <Shell onBack={back}>
232	      <div className="enter" style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
233	        {/* Event summary */}
234	        <Card style={{ display: 'grid', gap: 'var(--space-sm)' }}>
235	          <div className="type-title-lg">{event?.title || 'Untitled event'}</div>
236	          {event?.start && (
237	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
238	              <Clock size={15} strokeWidth={2} />
239	              {formatWhen(event.start, event.end)}
240	            </div>
241	          )}
242	          {event?.rooms && event.rooms.length > 0 && (
243	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
244	              <DoorOpen size={15} strokeWidth={2} />
245	              <span className="row__ellipsis">{event.rooms.join(', ')}</span>
246	            </div>
247	          )}
248	          {event?.description && (
249	            <div
250	              className="type-label-sm text-muted"
251	              style={{
252	                whiteSpace: 'pre-wrap',
253	                maxHeight: 72,
254	                overflow: 'hidden',
255	                borderTop: '1px solid var(--color-outline-variant)',
256	                paddingTop: 'var(--space-sm)',
257	              }}
258	            >
259	              {event.description}
260	            </div>
261	          )}
262	          {eid && (
263	            <Button
264	              variant="text"
265	              icon={<ExternalLink size={16} strokeWidth={2} />}
266	              onClick={() => void rpc({ type: 'NAVIGATE_TO_EVENT', eid })}
267	              // Negative left margin = the text button's own horizontal padding,
268	              // so the label optically aligns to the card edge while the hit area
269	              // and hover state layer stay intact (MD3 text-button placement).
270	              style={{ justifySelf: 'start', marginLeft: 'calc(-1 * var(--space-md))' }}
271	            >
272	              Open in Calendar
273	            </Button>
274	          )}
275	          {templates.length >= 2 && (
276	            <SelectField
277	              label="Email template (all guests)"
278	              value={currentTemplate}
279	              onChange={(e) => setEventTemplate(e.target.value)}
280	            >
281	              {templates.map((t) => (
282	                <option key={t.key} value={t.key}>
283	                  {t.name}
284	                  {t.isDefault ? ' (default)' : ''}
285	                </option>
286	              ))}
287	            </SelectField>
288	          )}
289	        </Card>
290	
291	        {/* Roster */}
292	        <section>
293	          <div
294	            className="type-label-sm text-muted"
295	            style={{ textTransform: 'uppercase', marginBottom: 4 }}
296	          >
297	            Guests · {included.length} getting a pass
298	          </div>
299	          {data.roster.length === 0 ? (
300	            <Card className="type-body text-muted">
301	              No guests on this event yet. Add attendees in Calendar, then reopen.
302	            </Card>
303	          ) : (
304	            <div className="roster">
305	              {data.roster.map((g) => (
306	                <RosterRow
307	                  key={g.email}
308	                  guest={g}
309	                  onChange={(edit) => patchGuest(g.email, edit)}
310	                />
311	              ))}
312	            </div>
313	          )}
314	        </section>
315	
316	        {/* Send result */}
317	        {send.isSuccess && <SendSummary result={send.data} />}
318	        {send.isError && (
319	          <div className="banner banner--error" role="alert">
320	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
321	            <span className="type-body">{(send.error as Error).message}</span>
322	          </div>
323	        )}
324	      </div>
325	
326	      {/* Sticky action bar */}
327	      <footer
328	        style={{
329	          padding: 'var(--space-md) var(--space-lg)',
330	          borderTop: '1px solid var(--color-outline-variant)',
331	          background: 'var(--color-surface-lowest)',
332	        }}
333	      >
334	        {nothingToDo && (
335	          <div
336	            className="banner banner--info"
337	            role="status"
338	            style={{ marginBottom: 'var(--space-sm)' }}
339	          >
340	            <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
341	            <span className="type-body">Up to date. No changes to send.</span>
342	          </div>
343	        )}
344	        <Button
345	          block
346	          loading={preview.isPending}
347	          disabled={!canSend}
348	          icon={<Eye size={18} strokeWidth={2} />}
349	          onClick={openReview}
350	        >
351	          {preview.isPending
352	            ? 'Loading preview…'
353	            : `${reviewLabel}${included.length ? ` (${included.length})` : ''}`}
354	        </Button>
355	        {preview.isError && (
356	          <div className="type-label-sm" style={{ color: 'var(--color-error)', textAlign: 'center', marginTop: 6 }}>
357	            {(preview.error as Error).message}
358	          </div>
359	        )}
360	        {sentCount > 0 && !send.isPending && !nothingToDo && (
361	          <div className="type-label-sm text-muted" style={{ textAlign: 'center', marginTop: 6 }}>
362	            {sentCount} pass{sentCount > 1 ? 'es' : ''} already issued
363	          </div>
364	        )}
365	      </footer>
366	
367	      {previewData && (
368	        <PreviewSheet
369	          preview={previewData.preview}
370	          recipient={previewData.recipient}
371	          totalCount={included.length}
372	          sending={send.isPending}
373	          onSend={() =>
374	            send.mutate(undefined, {
375	              onSuccess: () => {
376	                setPreviewData(null);
377	                setEdited(false);
378	              },
379	            })
380	          }
381	          onClose={() => setPreviewData(null)}
382	        />
383	      )}
384	    </Shell>
385	  );
386	}
387	
388	// ───────────────────────── sub-components ─────────────────────────
389	
390	function Shell({ children, onBack }: { children: React.ReactNode; onBack?: () => void }) {
391	  return (
392	    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minWidth: 320 }}>
393	      <header
394	        style={{
395	          display: 'flex',
396	          alignItems: 'center',
397	          gap: 'var(--space-sm)',
398	          padding: 'var(--space-md) var(--space-lg)',
399	          borderBottom: '1px solid var(--color-outline-variant)',
400	          flex: '0 0 auto',
401	        }}
402	      >
403	        {onBack ? (
404	          <IconButton label="Back to events" onClick={onBack}>
405	            <ArrowLeft size={20} strokeWidth={2} />
406	          </IconButton>
407	        ) : (
408	          <Logo size={26} />
409	        )}
410	        <span className="type-title">Auxilio Visitor</span>
411	        <span style={{ flex: 1 }} />
412	        <AccountMenu />
413	      </header>
414	      <div style={{ flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
415	        {children}
416	      </div>
417	    </div>
418	  );
419	}
420	
421	function LoadingState({ label }: { label: string }) {
422	  return (
423	    <div
424	      style={{
425	        flex: 1,
426	        display: 'flex',
427	        flexDirection: 'column',
428	        alignItems: 'center',
429	        justifyContent: 'center',
430	        gap: 'var(--space-md)',
431	        color: 'var(--color-on-surface-variant)',
432	      }}
433	    >
434	      <span className="spinner" style={{ width: 22, height: 22 }} />
435	      <span className="type-body">{label}</span>
436	    </div>
437	  );
438	}
439	
440	function RosterSkeleton({ title }: { title?: string }) {
441	  return (
442	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
443	      <Card style={{ display: 'grid', gap: 8 }}>
444	        <span className="type-title-lg">{title || 'Loading event…'}</span>
445	        <Skeleton width="60%" />
446	      </Card>
447	      <Card style={{ display: 'grid', gap: 'var(--space-lg)' }}>
448	        {[0, 1, 2].map((i) => (
449	          <div key={i} style={{ display: 'flex', gap: 'var(--space-md)', alignItems: 'center' }}>
450	            <Skeleton width={44} height={24} radius={999} />
451	            <div style={{ flex: 1, display: 'grid', gap: 6 }}>
452	              <Skeleton width="50%" />
453	              <Skeleton width="70%" height={12} />
454	            </div>
455	          </div>
456	        ))}
457	      </Card>
458	    </div>
459	  );
460	}
461	
462	function NoticeState({
463	  title,
464	  body,
465	  onRetry,
466	  guests,
467	}: {
468	  title: string;
469	  body: string;
470	  onRetry?: () => void;
471	  guests?: string[];
472	}) {
473	  return (
474	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-md)' }}>
475	      <Card style={{ display: 'grid', gap: 'var(--space-sm)', padding: 'var(--space-xl)' }}>
476	        <span className="type-title-lg">{title}</span>
477	        <span className="type-body text-muted">{body}</span>
478	        {onRetry && (
479	          <Button
480	            variant="tonal"
481	            icon={<RefreshCw size={16} strokeWidth={2} />}
482	            onClick={onRetry}
483	            style={{ justifySelf: 'start', marginTop: 'var(--space-xs)' }}
484	          >
485	            Check again
486	          </Button>
487	        )}
488	      </Card>
489	      {guests && guests.length > 0 && (
490	        <Card style={{ display: 'grid', gap: 'var(--space-xs)' }}>
491	          <span className="type-label-sm text-muted" style={{ textTransform: 'uppercase' }}>
492	            Guests detected on this event
493	          </span>
494	          {guests.map((g) => (
495	            <span key={g} className="type-body row__ellipsis">{g}</span>
496	          ))}
497	        </Card>
498	      )}
499	    </div>
500	  );
501	}
502	
503	function ErrorState({ message, onRetry }: { message: string; onRetry: () => void }) {
504	  return (
505	    <div style={{ padding: 'var(--space-lg)' }}>
506	      <div className="banner banner--error" role="alert" style={{ marginBottom: 'var(--space-md)' }}>
507	        <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
508	        <span className="type-body">{message}</span>
509	      </div>
510	      <Button variant="tonal" icon={<RefreshCw size={16} strokeWidth={2} />} onClick={onRetry}>
511	        Try again
512	      </Button>
513	    </div>
514	  );
515	}
516	
517	function SendSummary({
518	  result,
519	}: {
520	  result: import('@/lib/types').SendResponse;
521	}) {
522	  return (
523	    <div
524	      className="banner"
525	      role="status"
526	      aria-live="polite"
527	      style={{ background: 'var(--color-success-container)', color: 'var(--color-on-success-container)' }}
528	    >
529	      <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
530	      <div>
531	        <div className="type-label">
532	          {result.created.length > 0
533	            ? `${result.created.length} pass${result.created.length > 1 ? 'es' : ''} sent`
534	            : result.cancelled.length > 0
535	              ? 'Passes updated'
536	              : 'No changes'}
537	          {result.cancelled.length > 0 && ` · ${result.cancelled.length} cancelled`}
538	        </div>
539	        {result.failed.length > 0 && (
540	          <ul className="type-label-sm" style={{ margin: '4px 0 0', paddingLeft: 16 }}>
541	            {result.failed.map((f) => (
542	              <li key={f.visitorEmail}>
543	                {f.visitorEmail}: {f.reason}
544	              </li>
545	            ))}
546	          </ul>
547	        )}
548	      </div>
549	    </div>
550	  );
551	}
552	
553	function formatWhen(start: string, end?: string): string {
554	  const allDay = !start.includes('T');
555	  const s = new Date(start);
556	  const date = s.toLocaleDateString(undefined, { weekday: 'short', day: 'numeric', month: 'short' });
557	  if (allDay) return `${date} · All day`;
558	  const t = (d: Date) => d.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
559	  return end ? `${date} · ${t(s)} to ${t(new Date(end))}` : `${date} · ${t(s)}`;
560	}
