    const results = await Promise.all(todo.map((e) => resolveOne(e, accessToken)));
    todo.forEach((email, i) => {
      const person = results[i];
      mem.set(email, person);
      persisted[email] = { person, at: Date.now() };
      if (person) out[email] = person;
    });
    await saveCache(persisted);
  }
  return out;
}

