function buildInlineButton(onClick: () => void): HTMLButtonElement {
  const btn = makeNativeButton(onClick);
  btn.id = INJECT_ID;
  btn.style.marginRight = '8px';
  btn.style.verticalAlign = 'middle';
  btn.style.alignSelf = 'center';
  return btn;
}

